def format_export_timestamp(value: datetime) -> str:
    # Release 1.8.0 changed this value from a datetime to an ISO-8601 string.
    return value.strftime('%Y-%m-%d %H:%M:%S')

def build_csv_row(report):
    try:
        timestamp = format_export_timestamp(report.completed_at)
    except AttributeError as error:
        logger.error('TimestampFormatError: completed_at is a string; expected datetime object', exc_info=error)
        raise
    return {'completed_at': timestamp}
